UPDATE public.products SET image_url = '/__l5e/assets-v1/208b2608-fc22-493c-ac23-dbf938168e39/bottle-amber.png' WHERE category_id IN (SELECT id FROM public.categories WHERE slug = 'men'); UPDATE public.products SET image_url = '/__l5e/assets-v1/766db44e-1673-4752-a7dc-335c399a8189/bottle-silver.jpg' WHERE category_id IN (SELECT id FROM public.categories WHERE slug IN ('women','unisex')) OR category_id IS NULL;